function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;

    // Precompute teleportTo for each cell
    const teleportTo = [];
    for (let i = 0; i < m; i++) {
        teleportTo[i] = [];
        for (let j = 0; j < n; j++) {
            teleportTo[i][j] = [];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= grid[i][j]) {
                        teleportTo[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    // Dijkstra's algorithm
    const dist = new Array(m).fill(0).map(() => new Array(n).fill(0).map(() => new Array(k + 1).fill(Infinity)));
    dist[0][0][0] = 0;

    // Priority queue: [cost, i, j, t]
    class PriorityQueue {
        constructor() {
            this.heap = [];
        }
        push(value) {
            this.heap.push(value);
            this.heapifyUp(this.heap.length - 1);
        }
        pop() {
            if (this.heap.length === 0) return null;
            const min = this.heap[0];
            this.heap[0] = this.heap.pop();
            this.heapifyDown(0);
            return min;
        }
        heapifyUp(index) {
            while (index > 0) {
                const parentIndex = Math.floor((index - 1) / 2);
                if (this.heap[parentIndex][0] <= this.heap[index][0]) {
                    break;
                }
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            }
        }
        heapifyDown(index) {
            const length = this.heap.length;
            while (index < length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }
        isEmpty() {
            return this.heap.length === 0;
        }
    }

    const pq = new PriorityQueue();
    pq.push([0, 0, 0, 0]);

    while (!pq.isEmpty()) {
        const [cost, i, j, t] = pq.pop();
        if (i === m - 1 && j === n - 1) {
            return cost;
        }
        if (cost > dist[i][j][t]) {
            continue;
        }

        // Regular moves: right and down
        // Right
        if (j + 1 < n) {
            const newCost = cost + grid[i][j + 1];
            if (newCost < dist[i][j + 1][t]) {
                dist[i][j + 1][t] = newCost;
                pq.push([newCost, i, j + 1, t]);
            }
        }
        // Down
        if (i + 1 < m) {
            const newCost = cost + grid[i + 1][j];
            if (newCost < dist[i + 1][j][t]) {
                dist[i + 1][j][t] = newCost;
                pq.push([newCost, i + 1, j, t]);
            }
        }

        // Teleportation
        if (t < k) {
            for (const [x, y] of teleportTo[i][j]) {
                const newT = t + 1;
                if (cost < dist[x][y][newT]) {
                    dist[x][y][newT] = cost;
                    pq.push([cost, x, y, newT]);
                }
            }
        }
    }

    return -1;
}

